/**
 * SKF Quick Update Command
 * Replaces SKF files and recompiles agents without re-prompting.
 * Preserves config.yaml and sidecar state.
 */

const chalk = require('chalk');
const path = require('node:path');
const fs = require('fs-extra');
const yaml = require('js-yaml');
const { Installer } = require('../lib/installer');
const { UI } = require('../lib/ui');

const SKF_FOLDER = '_bmad/skf';

module.exports = {
  command: 'update',
  description: 'Update SKF files and recompile agents (preserves config and sidecar)',
  options: [],
  action: async () => {
    try {
      const projectDir = process.cwd();
      const skfDir = path.join(projectDir, SKF_FOLDER);

      if (!(await fs.pathExists(skfDir))) {
        console.log(chalk.yellow('\n  SKF is not installed in this directory.'));
        console.log(chalk.dim('  Run: npx bmad-module-skill-forge install\n'));
        process.exit(0);
        return;
      }

      console.log('');
      console.log(chalk.cyan.bold('  Skill Forge — Quick Update'));
      console.log(chalk.dim('  Replacing SKF files, preserving config and sidecar.\n'));

      const installer = new Installer();
      const result = await installer.install({
        projectDir,
        skfFolder: SKF_FOLDER,
        _action: 'update',
      });

      if (result && result.success) {
        // Read config to get IDEs for post-update notes
        let ides = [];
        try {
          const configContent = await fs.readFile(path.join(skfDir, 'config.yaml'), 'utf8');
          const config = yaml.load(configContent);
          ides = config?.ides || [];
        } catch {
          /* use empty */
        }
        const ui = new UI();
        ui.displaySuccess(SKF_FOLDER, ides, 'update');
      }

      process.exit(0);
    } catch (error) {
      console.error(chalk.red('\nUpdate failed:'), error.message);
      process.exit(1);
    }
  },
};

/**
 * SKF Version Check
 * Async, non-blocking check against the npm registry.
 * Returns a promise that resolves to an update notice string (or null).
 */

const https = require('node:https');
const chalk = require('chalk');

const PACKAGE_NAME = 'bmad-module-skill-forge';
const REGISTRY_URL = `https://registry.npmjs.org/${PACKAGE_NAME}/latest`;
const TIMEOUT_MS = 3000;

function fetchLatestVersion() {
  return new Promise((resolve) => {
    const req = https.get(REGISTRY_URL, { timeout: TIMEOUT_MS }, (res) => {
      if (res.statusCode !== 200) {
        resolve(null);
        res.resume();
        return;
      }

      let data = '';
      res.on('data', (chunk) => {
        data += chunk;
      });
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          resolve(json.version || null);
        } catch {
          resolve(null);
        }
      });
    });

    req.on('error', () => resolve(null));
    req.on('timeout', () => {
      req.destroy();
      resolve(null);
    });
  });
}

function compareVersions(current, latest) {
  const parse = (v) => v.replace(/^v/, '').split('.').map(Number);
  const [cMajor, cMinor, cPatch] = parse(current);
  const [lMajor, lMinor, lPatch] = parse(latest);

  if (lMajor > cMajor) return true;
  if (lMajor === cMajor && lMinor > cMinor) return true;
  if (lMajor === cMajor && lMinor === cMinor && lPatch > cPatch) return true;
  return false;
}

/**
 * Start an async version check. Call the returned function after your
 * command finishes to print the update notice (if any).
 */
function startVersionCheck(currentVersion) {
  const checkPromise = fetchLatestVersion().then((latestVersion) => {
    if (!latestVersion || !compareVersions(currentVersion, latestVersion)) {
      return null;
    }
    return (
      '\n' +
      chalk.yellow(`  Update available: ${chalk.dim(currentVersion)} → ${chalk.green(latestVersion)}`) +
      '\n' +
      chalk.dim(`  Run: npx bmad-module-skill-forge@latest install`) +
      '\n'
    );
  });

  return async function printIfReady() {
    try {
      const notice = await checkPromise;
      if (notice) {
        process.stderr.write(notice);
      }
    } catch {
      // Never block or fail the CLI for a version check
    }
  };
}

module.exports = { startVersionCheck, compareVersions };
